sql:
SELECT county_id, estimate
FROM demographic_datasets
WHERE line_type = 'T';

SELECT household_income_name, description
FROM household_incomes
ORDER BY household_income_name;

SELECT AVG(estimate) AS average_estimate
FROM demographic_datasets
WHERE household_income = '30% AMI or less';

external_knowledge:
- 'Highest population' refers to the top 10 counties by population;
- 'Most populous states' refers to the top 5 states by population;
- 'Accessed more than 100 times' indicates significant user interest or engagement with the data;
- 'Survey data from the Census Bureau in 2020' specifies the data source and year.

- "Explorers" refers to users who have accessed datasets;
- "Digital landscapes" refers to datasets;
- "Most frequently visited" refers to datasets with the highest access counts.

- 'line_type' 'S' refers to a specific type of demographic data;
- 'tenure' 'Owner' indicates the data is for property owners;
- 'overcrowding' 'All' means the data includes all types of overcrowding statuses.

